-- Sychronize temp table and real table by            --
-- inserting, deleting, and updating as necessary     --
--------------------------------------------------------

INSERT INTO PSP_PMT_TEMPLATE_BANKACCOUNT
   (PMT_TEMPLATE_BANKACCOUNT_SEQ, VERSION, CREATOR_ID, CREATED_DATE, MODIFIER_ID, MODIFIED_DATE,REALM_ID, EFFECTIVE_DATE, EXPIRATION_DATE, SOURCE_BANK_ACCOUNT_ID, STATUS_CD, STATUS_EFFECTIVE_DATE, PAYMENT_TEMPLATE_FK, BANK_ACCOUNT_FK)
SELECT
    PMT_TEMPLATE_BANKACCOUNT_SEQ, VERSION, CREATOR_ID, CREATED_DATE, MODIFIER_ID, MODIFIED_DATE,REALM_ID, EFFECTIVE_DATE, EXPIRATION_DATE, SOURCE_BANK_ACCOUNT_ID, STATUS_CD, STATUS_EFFECTIVE_DATE, PAYMENT_TEMPLATE_FK, BANK_ACCOUNT_FK
FROM
   TEMP_PSP_PMT_TEMPLATE_BANKACCT tt
WHERE
   tt.PMT_TEMPLATE_BANKACCOUNT_SEQ NOT IN (SELECT PMT_TEMPLATE_BANKACCOUNT_SEQ FROM PSP_PMT_TEMPLATE_BANKACCOUNT)

;

UPDATE PSP_PMT_TEMPLATE_BANKACCOUNT rt
SET (VERSION, CREATOR_ID, CREATED_DATE, MODIFIER_ID, MODIFIED_DATE,REALM_ID, EFFECTIVE_DATE, EXPIRATION_DATE, SOURCE_BANK_ACCOUNT_ID, STATUS_CD, STATUS_EFFECTIVE_DATE, PAYMENT_TEMPLATE_FK, BANK_ACCOUNT_FK) =
(SELECT  tt.VERSION, tt.CREATOR_ID, tt.CREATED_DATE, tt.MODIFIER_ID, tt.MODIFIED_DATE,tt.REALM_ID, tt.EFFECTIVE_DATE, tt.EXPIRATION_DATE, tt.SOURCE_BANK_ACCOUNT_ID, tt.STATUS_CD, tt.STATUS_EFFECTIVE_DATE, tt.PAYMENT_TEMPLATE_FK, tt.BANK_ACCOUNT_FK
 FROM TEMP_PSP_PMT_TEMPLATE_BANKACCT tt WHERE tt.PMT_TEMPLATE_BANKACCOUNT_SEQ = rt.PMT_TEMPLATE_BANKACCOUNT_SEQ)
 WHERE rt.PMT_TEMPLATE_BANKACCOUNT_SEQ IN (SELECT PMT_TEMPLATE_BANKACCOUNT_SEQ FROM TEMP_PSP_PMT_TEMPLATE_BANKACCT)
;

DELETE FROM PSP_PMT_TEMPLATE_BANKACCOUNT
WHERE PMT_TEMPLATE_BANKACCOUNT_SEQ NOT IN (SELECT PMT_TEMPLATE_BANKACCOUNT_SEQ FROM TEMP_PSP_PMT_TEMPLATE_BANKACCT)
;

